#include <iostream>
#include <string>
#include <vector>

// --- Interface 1: Drawable ---
class Drawable {
public:
    virtual ~Drawable() {}
    virtual void draw() const = 0;
};

// --- Interface 2: Updatable ---
class Updatable {
public:
    virtual ~Updatable() {}
    virtual void update(float deltaTime) = 0;
};

// --- Interface 3: Interactable ---
class Interactable {
public:
    virtual ~Interactable() {}
    virtual void interact() = 0;
};

// --- Interface 4: Attackable ---
class Attackable {
public:
    virtual ~Attackable() {}
    virtual void attack(Attackable& target) = 0;
    virtual void takeDamage(int damage) = 0;
    virtual bool isAlive() const = 0;
};

// --- Class implementing multiple interfaces ---
class Player : public Drawable, public Updatable, public Interactable, public Attackable {
private:
    std::string name;
    int health;
    int attackPower;
    float x, y;

public:
    Player(std::string n, int h, int a) 
        : name(n), health(h), attackPower(a), x(0), y(0) {}

    // Drawable
    void draw() const override {
        std::cout << "Drawing player " << name << " at position (" << x << ", " << y << ")" << std::endl;
    }

    // Updatable
    void update(float deltaTime) override {
        x += deltaTime * 5.0f;
        y += deltaTime * 3.0f;
        std::cout << "Player " << name << " updated (position: " << x << ", " << y << ")" << std::endl;
    }

    // Interactable
    void interact() override {
        std::cout << name << " interacts with the environment!" << std::endl;
    }

    // Attackable
    void attack(Attackable& target) override {
        std::cout << name << " attacks " << dynamic_cast<Player*>(&target)->getName() 
                  << " for " << attackPower << " damage!" << std::endl;
        target.takeDamage(attackPower);
    }

    void takeDamage(int damage) override {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage! (" << health << " HP left)" << std::endl;
    }

    bool isAlive() const override { return health > 0; }
    std::string getName() const { return name; }
};

// --- Enemy class implementing fewer interfaces ---
class Enemy : public Drawable, public Updatable, public Attackable {
private:
    std::string name;
    int health;
    int attackPower;
    float x, y;
    bool isAggro;

public:
    Enemy(std::string n, int h, int a) 
        : name(n), health(h), attackPower(a), x(0), y(0), isAggro(false) {}

    // Drawable
    void draw() const override {
        std::cout << "Drawing enemy " << name << " at (" << x << ", " << y << ")" 
                  << (isAggro ? " [AGGRO]" : "") << std::endl;
    }

    // Updatable
    void update(float deltaTime) override {
        if (isAggro) {
            x += deltaTime * 2.0f;
            y += deltaTime * 1.5f;
            std::cout << "Enemy " << name << " moves toward player!" << std::endl;
        }
    }

    // Attackable
    void attack(Attackable& target) override {
        std::cout << name << " attacks for " << attackPower << " damage!" << std::endl;
        target.takeDamage(attackPower);
    }

    void takeDamage(int damage) override {
        health -= damage;
        if (health < 0) health = 0;
        isAggro = true;
        std::cout << name << " took " << damage << " damage! (" << health << " HP left) [AGGRO]" << std::endl;
    }

    bool isAlive() const override { return health > 0; }

    void setAggro(bool aggro) { isAggro = aggro; }
};

// --- Object class for pure objects ---
class Chest : public Drawable, public Interactable {
private:
    std::string contents;
    bool isOpen;
    float x, y;

public:
    Chest(std::string contents, float x, float y) 
        : contents(contents), isOpen(false), x(x), y(y) {}

    void draw() const override {
        std::cout << "Drawing chest at (" << x << ", " << y << ")" 
                  << (isOpen ? " [OPEN]" : " [CLOSED]") << std::endl;
    }

    void interact() override {
        if (isOpen) {
            std::cout << "Chest is already open. Empty." << std::endl;
        } else {
            isOpen = true;
            std::cout << "You open the chest and find: " << contents << "!" << std::endl;
        }
    }
};

int main() {
    std::cout << "=== Interfaces via Abstract Classes ===" << std::endl;

    Player hero("Aragorn", 120, 20);
    Enemy goblin("Goblin", 30, 8);
    Chest chest("Health Potion", 10.0f, 5.0f);

    // Polymorphism with interfaces
    std::cout << "\n=== Drawing All ===" << std::endl;
    std::vector<Drawable*> drawables = {&hero, &goblin, &chest};
    for (Drawable* d : drawables) {
        d->draw();
    }

    std::cout << "\n=== Updating All ===" << std::endl;
    std::vector<Updatable*> updatables = {&hero, &goblin};
    for (Updatable* u : updatables) {
        u->update(0.1f);
    }

    std::cout << "\n=== Interacting ===" << std::endl;
    std::vector<Interactable*> interactables = {&hero, &chest};
    for (Interactable* i : interactables) {
        i->interact();
    }

    std::cout << "\n=== Combat (Attackable) ===" << std::endl;
    std::vector<Attackable*> combatants = {&hero, &goblin};
    hero.attack(goblin);

    // Chest is not Attackable, so it's not in the combat list

    std::cout << "\n=== Final Status ===" << std::endl;
    hero.draw();
    goblin.draw();
    chest.draw();

    return 0;
}

