phase2.explanation:
The interface has no virtual destructor. Deleting a pointer to an interface will not call the derived class destructor.

**The fix:**
```cpp
class Drawable {
public:
    virtual ~Drawable() {}  // ← Always add this!
    virtual void draw() const = 0;
};
```

**PlusPlus-chan says:**
"Every interface must have a virtual destructor. Without it, you're asking for undefined behavior. Always, always, always."

**This applies to:**
- All abstract classes
- All interfaces
- Any class with virtual functions

phase3.solution:
#include <iostream>
#include <string>
#include <vector>

class Drawable {
public:
    virtual ~Drawable() {}
    virtual void draw() const = 0;
};

class Resizable {
public:
    virtual ~Resizable() {}
    virtual void resize(double factor) = 0;
};

class Rotatable {
public:
    virtual ~Rotatable() {}
    virtual void rotate(double angle) = 0;
};

class Shape : public Drawable, public Resizable, public Rotatable {
private:
    std::string name;
    double size;
    double angle;

public:
    Shape(std::string n, double s) : name(n), size(s), angle(0) {}

    void draw() const override {
        std::cout << name << " (Size: " << size << ", Angle: " << angle << "°)" << std::endl;
    }

    void resize(double factor) override {
        size *= factor;
        std::cout << name << " resized to " << size << std::endl;
    }

    void rotate(double angleDeg) override {
        angle += angleDeg;
        std::cout << name << " rotated to " << angle << "°" << std::endl;
    }
};

int main() {
    Shape box("Box", 10.0);

    std::cout << "=== Shape Demo ===" << std::endl;
    box.draw();
    box.resize(1.5);
    box.rotate(45);
    box.draw();

    std::cout << "\n=== Polymorphic Draw ===" << std::endl;
    Drawable* drawables[] = {&box};
    for (Drawable* d : drawables) {
        d->draw();
    }

    return 0;
}
